commands.examples:
SELECT COUNT(*) FROM users;
SELECT COUNT(DISTINCT city) FROM users;
SELECT AVG(price), SUM(quantity) FROM order_items;

SELECT category, COUNT(*) AS total, AVG(price) AS avg_price
FROM products GROUP BY category HAVING COUNT(*) > 5;

SELECT department, STRING_AGG(name, ', ' ORDER BY name) AS members
FROM employees GROUP BY department;

SELECT STRING_AGG(DISTINCT tag, ', ') FROM article_tags WHERE article_id = 1;

SELECT department, ARRAY_AGG(name ORDER BY name) FROM employees GROUP BY department;

SELECT JSON_AGG(row_to_json(u)) FROM users u WHERE active = true;

SELECT JSON_OBJECT_AGG(key, value) FROM settings;
